svg.script:

// State Configuration
let currentAxis = 'pitch'; // 'pitch', 'roll', 'yaw'
let targetAngle = 0;
let currentAngle = 0;

// Animation variables
let lastTime = 0;
let mainRotorAngle = 0;
let tailRotorAngle = 0;

// Custom SVG Slider State
const SLIDER_WIDTH = 310;
const SLIDER_CENTER = 155;
let isDragging = false;

// Axis Configurations
const axisData = {
    'pitch': {
        color: '#3b82f6',
        title: 'PITCH CONTROL',
        subtitle: 'Adjust the Cyclic Stick (Forward/Back)',
        lblLeft: 'Nose Down (Fwd)',
        lblRight: 'Nose Up (Back)',
        min: -30,
        max: 30,
        infoTitle: 'Pitch (Lateral Axis)',
        infoDesc: 'Pitch is the up-and-down movement of the helicopter\'s nose. The pilot controls this by moving the <strong>Cyclic Stick</strong> forward or backward. This mechanically tilts the entire main rotor disc, directing the thrust vector forward (to accelerate) or backward (to slow down or reverse).'
    },
    'roll': {
        color: '#a855f7',
        title: 'ROLL CONTROL',
        subtitle: 'Adjust the Cyclic Stick (Left/Right)',
        lblLeft: 'Bank Left',
        lblRight: 'Bank Right',
        min: -30,
        max: 30,
        infoTitle: 'Roll (Longitudinal Axis)',
        infoDesc: 'Roll is the side-to-side tilting of the helicopter. The pilot controls this by moving the <strong>Cyclic Stick</strong> left or right. This tilts the main rotor disc laterally, directing thrust to the side to initiate a banking turn or a horizontal slide through the air.'
    },
    'yaw': {
        color: '#f97316',
        title: 'YAW CONTROL',
        subtitle: 'Adjust the Anti-Torque Pedals',
        lblLeft: 'Nose Left',
        lblRight: 'Nose Right',
        min: -45,
        max: 45,
        infoTitle: 'Yaw (Vertical Axis)',
        infoDesc: 'Yaw is the left or right rotation of the helicopter\'s nose around its vertical center. The pilot controls this using the <strong>Anti-torque Pedals</strong>, which adjust the blade pitch of the tail rotor. This increases or decreases sideways thrust, allowing the helicopter to pivot in place.'
    }
};

function initSimulation() {
    setAxis('pitch');
    requestAnimationFrame(animationLoop);
}

function setAxis(axis) {
    currentAxis = axis;
    const data = axisData[axis];

    // Reset Slider & Angles
    targetAngle = 0;
    currentAngle = 0;
    updateSliderVisuals(SLIDER_CENTER, 0);

    // Update Tabs
    document.querySelectorAll('.tab').forEach(el => el.classList.remove('active'));
    document.getElementById('tab-' + axis).classList.add('active');

    // Update Views
    document.getElementById('view-pitch').setAttribute('display', axis === 'pitch' ? 'block' : 'none');
    document.getElementById('view-roll').setAttribute('display', axis === 'roll' ? 'block' : 'none');
    document.getElementById('view-yaw').setAttribute('display', axis === 'yaw' ? 'block' : 'none');

    // Update Control Panel Text & Colors
    document.getElementById('ctrl-title').textContent = data.title;
    document.getElementById('ctrl-title').setAttribute('fill', data.color);
    document.getElementById('ctrl-subtitle').textContent = data.subtitle;
    document.getElementById('slider-label-left').textContent = data.lblLeft;
    document.getElementById('slider-label-right').textContent = data.lblRight;

    document.getElementById('slider-fill').setAttribute('stroke', data.color);
    document.getElementById('slider-thumb').setAttribute('stroke', data.color);
    document.getElementById('slider-val').setAttribute('fill', data.color);

    // Toggle Pilot Controls Graphic
    if (axis === 'yaw') {
        document.getElementById('graphic-cyclic').setAttribute('display', 'none');
        document.getElementById('graphic-pedals').setAttribute('display', 'block');
        document.getElementById('pilot-action-text').textContent = 'PILOT ACTION: ANTI-TORQUE PEDALS';
    } else {
        document.getElementById('graphic-cyclic').setAttribute('display', 'block');
        document.getElementById('graphic-pedals').setAttribute('display', 'none');
        document.getElementById('pilot-action-text').textContent = 'PILOT ACTION: CYCLIC STICK';

        // Reset cyclic stick visual
        document.getElementById('cyclic-stick').setAttribute('transform', 'rotate(0)');
    }

    // Update Bottom Info Panel
    document.getElementById('info-badge').style.backgroundColor = data.color;
    document.getElementById('info-title').textContent = data.infoTitle;
    document.getElementById('info-desc').innerHTML = data.infoDesc;
}

// Slider Drag Handling
function getClientX(evt) {
    if (evt.touches && evt.touches.length > 0) return evt.touches[0].clientX;
    if (evt.changedTouches && evt.changedTouches.length > 0) return evt.changedTouches[0].clientX;
    return evt.clientX;
}
function getClientY(evt) {
    if (evt.touches && evt.touches.length > 0) return evt.touches[0].clientY;
    if (evt.changedTouches && evt.changedTouches.length > 0) return evt.changedTouches[0].clientY;
    return evt.clientY;
}

function startDrag(evt) {
    isDragging = true;
    updateDrag(evt);
}
function startDragTouch(evt) {
    evt.preventDefault();
    isDragging = true;
    updateDrag(evt);
}

function onMouseMove(evt) {
    if (isDragging) updateDrag(evt);
}
function onMouseUp(evt) {
    isDragging = false;
}
function onTouchMove(evt) {
    if (isDragging) { evt.preventDefault(); updateDrag(evt); }
}
function onTouchEnd(evt) {
    isDragging = false;
}

function updateDrag(evt) {
    const svg = document.getElementById('main-svg');
    const pt = svg.createSVGPoint();
    pt.x = getClientX(evt);
    pt.y = getClientY(evt);
    const svgP = pt.matrixTransform(svg.getScreenCTM().inverse());

    // Sliders track starts at x=810 in the main SVG
    let localX = svgP.x - 810;
    if (localX < 0) localX = 0;
    if (localX > SLIDER_WIDTH) localX = SLIDER_WIDTH;

    const data = axisData[currentAxis];
    // Map [0, SLIDER_WIDTH] to [min, max]
    targetAngle = data.min + (localX / SLIDER_WIDTH) * (data.max - data.min);

    updateSliderVisuals(localX, targetAngle);
}

function updateSliderVisuals(x, angle) {
    document.getElementById('slider-fill').setAttribute('x1', SLIDER_CENTER);
    document.getElementById('slider-fill').setAttribute('x2', x);
    document.getElementById('slider-thumb').setAttribute('cx', x);
    document.getElementById('slider-val').textContent = Math.round(angle) + '°';
}

// 60fps Animation Loop for Physics Lerping and Rotor Spinning
function animationLoop(timestamp) {
    if (!lastTime) lastTime = timestamp;
    const dt = timestamp - lastTime || 16;
    lastTime = timestamp;

    // Lerp current angle towards target angle for smooth physical motion
    currentAngle += (targetAngle - currentAngle) * 0.15;

    // Apply rotations to the active helicopter model and pilot controls
    if (currentAxis === 'pitch') {
        document.getElementById('model-pitch').setAttribute('transform', `rotate(${currentAngle}, -10, -10)`);
        // Move Cyclic stick (push forward = nose down = negative angle)
        document.getElementById('cyclic-stick').setAttribute('transform', `rotate(${currentAngle})`);
    } 
    else if (currentAxis === 'roll') {
        document.getElementById('model-roll').setAttribute('transform', `rotate(${currentAngle}, 0, -10)`);
        // Move Cyclic stick laterally
        document.getElementById('cyclic-stick').setAttribute('transform', `rotate(${currentAngle})`);
    } 
    else if (currentAxis === 'yaw') {
        document.getElementById('model-yaw').setAttribute('transform', `rotate(${currentAngle}, -30, 0)`);

        // Animate Pedals (Push right pedal forward = nose right = positive angle)
        // Left pedal moves opposite
        const pedalMove = currentAngle * 0.6; // Scale down for visual
        document.getElementById('pedal-left').setAttribute('transform', `translate(-40, ${pedalMove})`);
        document.getElementById('pedal-right').setAttribute('transform', `translate(40, ${-pedalMove})`);

        // Adjust Yaw thrust vector dynamically based on yaw intensity
        const baseThrust = 40;
        // If nose goes right (+ angle), tail needs to be pushed LEFT (negative thrust line)
        const extraThrust = currentAngle * 1.5; 
        let thrustEnd = 220 + baseThrust - extraThrust;
        document.getElementById('yaw-thrust').setAttribute('x2', thrustEnd);

        // Flip marker direction if thrust reverses entirely
        if (thrustEnd < 220) {
             // Simple visual hack: If line crosses origin, it looks reversed.
        }
    }

    // Animate spinning rotors (continuous)
    mainRotorAngle = (mainRotorAngle + 20) % 360;
    tailRotorAngle = (tailRotorAngle + 35) % 360;

    // Because we are using 2D orthogonal views, spinning is faked via scaling/dasharrays
    // Side View Pitch
    const bladeScalePitch = Math.cos(mainRotorAngle * Math.PI / 180);
    document.getElementById('spin-pitch').setAttribute('transform', `scale(${bladeScalePitch}, 1)`);

    // Front View Roll
    const bladeScaleRoll = Math.cos(mainRotorAngle * Math.PI / 180);
    document.getElementById('spin-roll').setAttribute('transform', `scale(${bladeScaleRoll}, 1)`);

    // Top View Yaw (Spinning tail rotor line, main rotor is a circle so it's fine)
    const tailScaleYaw = Math.cos(tailRotorAngle * Math.PI / 180);
    // Translate to center of tail rotor, scale, translate back
    document.getElementById('spin-yaw-tail').setAttribute('transform', `translate(220,0) scale(1, ${tailScaleYaw}) translate(-220,0)`);

    // Main rotor in top view: spin a line
    document.getElementById('spin-yaw-main').setAttribute('transform', `rotate(${mainRotorAngle}, -30, 0)`);

    requestAnimationFrame(animationLoop);
}
